mapper.select:
SELECT * FROM learning_log
WHERE textbook_id = #{textbookId}
AND add_datetime BETWEEN CAST(#{startTime} AS TIMESTAMP) AND CAST(#{endTime} AS TIMESTAMP)

WITH textbook_correct_rate AS ( -- 修正后的答题正确率统计 SELECT tqb.textbook_id, -- 平均得分率（避免扇入问题） ROUND(AVG( CASE WHEN qbl.total_score > 0 THEN sfg.final_score * 1.0 / qbl.total_score ELSE 0 END ) * 100, 2) as question_correct_rate, -- 同时统计合格率（可选） CASE WHEN COUNT(*) > 0 THEN ROUND( SUM(CASE WHEN qbl.total_score > 0 AND sfg.final_score * 1.0 / qbl.total_score >= 0.6 THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2 ) ELSE 0 END as pass_rate FROM teaching_question_bank tqb -- 题库总分 INNER JOIN ( SELECT bank_id, SUM(score) as total_score FROM questions_banks_list GROUP BY bank_id ) qbl ON tqb.id = qbl.bank_id -- 学生答题（每个学生取最高分） LEFT JOIN ( SELECT bank_id, student_id, MAX(final_score) as final_score FROM student_final_grade
WHERE operation_datetime BETWEEN #{startTime} AND #{endTime}
GROUP BY bank_id, student_id ) sfg ON tqb.id = sfg.bank_id WHERE tqb.status = 1 GROUP BY tqb.textbook_id ), textbook_material_stats AS ( -- 合并所有素材统计（大幅减少JOIN次数） SELECT mtm.textbook_id, -- 素材总数 COUNT(*) as material_count, -- 各类素材数量 COUNT(CASE WHEN LOWER(tm.type) = 'image' THEN 1 END) as image_count, COUNT(CASE WHEN LOWER(tm.type) = 'video' THEN 1 END) as video_count, COUNT(CASE WHEN LOWER(tm.type) = 'audio' THEN 1 END) as audio_count, COUNT(CASE WHEN LOWER(tm.type) = '3dmodel' THEN 1 END) as model3d_count, COUNT(CASE WHEN LOWER(tm.type) = 'link' THEN 1 END) as link_count, COUNT(CASE WHEN LOWER(tm.type) = 'ppt' THEN 1 END) as ppt_count, COUNT(CASE WHEN LOWER(tm.type) = 'pdf' THEN 1 END) as pdf_count, COUNT(CASE WHEN LOWER(tm.type) = 'word' THEN 1 END) as word_count, COUNT(CASE WHEN LOWER(tm.type) = 'excel' THEN 1 END) as excel_count, COUNT(CASE WHEN LOWER(tm.type) = 'h5' THEN 1 END) as h5_count, COUNT(CASE WHEN LOWER(tm.type) = 'simulation' THEN 1 END) as simulation_count, COUNT(CASE WHEN LOWER(tm.type) NOT IN ( 'image', 'video', 'audio', '3dmodel', 'link', 'ppt', 'pdf', 'word', 'excel', 'h5', 'simulation' ) THEN 1 END) as other_count FROM materials_textbook_mapping mtm INNER JOIN teaching_materials tm ON mtm.material_id = tm.id
WHERE tm.operation_datetime BETWEEN #{startTime} AND #{endTime}
GROUP BY mtm.textbook_id ), textbook_discussion_stats AS ( -- 合并讨论相关统计 SELECT dt.textbook_id, -- 教学活动数量 COUNT(DISTINCT CASE WHEN dt.identity_type = 1 THEN dt.id END) as teaching_activity_count, -- 交流反馈总数（回复数） COUNT(dtr.id) as communication_feedback_count, -- 交流反馈参与人数 COUNT(DISTINCT dtr.creator) as communication_participation_count FROM discussion_topic dt LEFT JOIN discussion_topic_reply dtr ON dt.id = dtr.topic_id
WHERE (dt.operation_datetime BETWEEN #{startTime} AND #{endTime}) OR (dtr.operation_datetime BETWEEN #{startTime} AND #{endTime})
GROUP BY dt.textbook_id ) SELECT t.id AS "textbookId", t.textbook_name AS "textbookName", -- 阅读人数（修正：统计学生用户） COALESCE(( SELECT COUNT(DISTINCT ll.creator) FROM learning_log ll INNER JOIN student s ON ll.creator = s.user_id -- 确保是学生 WHERE ll.textbook_id = t.id
AND ll.add_datetime BETWEEN #{startTime} AND #{endTime}
), 0) as "readerCount", -- 教学活动数量 COALESCE(ds.teaching_activity_count, 0) as "teachingActivityCount", -- 素材总数 COALESCE(ms.material_count, 0) as "materialCount", -- 交流反馈数量 COALESCE(ds.communication_feedback_count, 0) as "communicationFeedbackCount", -- 教学思政数量 COALESCE(( SELECT COUNT(*) FROM ideological_material im WHERE im.textbook_id = t.id
AND im.operation_datetime BETWEEN #{startTime} AND #{endTime}
), 0) as "ideologicalMaterialCount", -- 答题正确率（修正后） COALESCE(cr.question_correct_rate, 0) as "questionCorrectRate", -- 交流反馈参与量 COALESCE(ds.communication_participation_count, 0) as "communicationParticipationCount", -- 知识点批注量 COALESCE(( SELECT COUNT(*) FROM teacher_annotation ta WHERE ta.textbook_id = t.id
AND ta.operation_datetime BETWEEN #{startTime} AND #{endTime}
), 0) as "annotationCount", -- 各类素材数量 COALESCE(ms.image_count, 0) as "imageMaterialCount", COALESCE(ms.video_count, 0) as "videoMaterialCount", COALESCE(ms.audio_count, 0) as "audioMaterialCount", COALESCE(ms.model3d_count, 0) as "model3dMaterialCount", COALESCE(ms.link_count, 0) as "linkMaterialCount", COALESCE(ms.ppt_count, 0) as "pptMaterialCount", COALESCE(ms.pdf_count, 0) as "pdfMaterialCount", COALESCE(ms.word_count, 0) as "wordMaterialCount", COALESCE(ms.excel_count, 0) as "excelMaterialCount", COALESCE(ms.h5_count, 0) as "h5MaterialCount", COALESCE(ms.simulation_count, 0) as "simulationMaterialCount", COALESCE(ms.other_count, 0) as "otherMaterialCount", -- 额外统计：教材创建时间、作者等（根据需要添加） t.creator as "creatorId", (SELECT real_name FROM "user" WHERE id = t.creator) as "creatorName", t.add_datetime as "createTime", t.release_status as "releaseStatus" FROM textbook t LEFT JOIN textbook_correct_rate cr ON t.id = cr.textbook_id LEFT JOIN textbook_material_stats ms ON t.id = ms.textbook_id LEFT JOIN textbook_discussion_stats ds ON t.id = ds.textbook_id WHERE t.release_status = '1'
AND t.textbook_name LIKE CONCAT('%', #{textbookName}, '%')
AND t.creator = #{creatorId}
AND t.add_datetime BETWEEN #{startTime} AND #{endTime}
ORDER BY t.textbook_name
